rule.query:
{
  "selection": {
    "Image|endswith": "/osascript",
    "CommandLine|contains|all": [
      " -e ",
      "clipboard"
    ]
  },
  "filter_optional_opencode": {
    "ParentImage|endswith": "opencode",
    "CommandLine|contains|all": [
      "osascript",
      " -e ",
      "set imageData to the clipboard",
      "set fileRef"
    ]
  },
  "condition": "selection and not 1 of filter_optional_*"
}
